import { cva } from "class-variance-authority";
import type { CSSProperties, ReactNode } from "react";
import { cn } from "./lib/utils";
import { renderBall } from "./spinners/ball";
import { renderBars } from "./spinners/bars";
import { renderCircle } from "./spinners/circle";
import { renderClap } from "./spinners/clap";
import { renderClassic } from "./spinners/classic";
import { renderComb } from "./spinners/comb";
import { renderCube } from "./spinners/cube";
import { renderDomino } from "./spinners/domino";
import { renderFill } from "./spinners/fill";
import { renderFirework } from "./spinners/firework";
import { renderFlag } from "./spinners/flag";
import { renderFlapper } from "./spinners/flapper";
import { renderGoo } from "./spinners/goo";
import { renderGrid } from "./spinners/grid";
import { renderGuard } from "./spinners/guard";
import { renderHeart } from "./spinners/heart";
import { renderHoop } from "./spinners/hoop";
import { renderImpulse } from "./spinners/impulse";
import { renderJellyfish } from "./spinners/jellyfish";
import { renderMagic } from "./spinners/magic";
import { renderMetro } from "./spinners/metro";
import { renderPong } from "./spinners/pong";
import { renderPulse } from "./spinners/pulse";
import { renderPush } from "./spinners/push";
import { renderRainbow } from "./spinners/rainbow";
import { renderRing } from "./spinners/ring";
import { renderRotate } from "./spinners/rotate";
import { renderSequence } from "./spinners/sequence";
import { renderSphere } from "./spinners/sphere";
import { renderSpiral } from "./spinners/spiral";
import { renderStage } from "./spinners/stage";
import { renderSwap } from "./spinners/swap";
import { renderSwish } from "./spinners/swish";
import { renderTrace } from "./spinners/trace";
import { renderWave } from "./spinners/wave";
import { renderWhisper } from "./spinners/whisper";
import type { InternalRenderProps, SpinnerProps, SpinnerVariant } from "./types";

const spinnerVariants = cva("inline-flex items-center justify-center", {
  variants: {
    size: {
      sm: "",
      md: "",
      lg: "",
      xl: "",
    },
  },
  defaultVariants: {
    size: "md",
  },
});

const renderers: Record<SpinnerVariant, (props: InternalRenderProps) => ReactNode> = {
  ball: renderBall,
  grid: renderGrid,
  swap: renderSwap,
  bars: renderBars,
  wave: renderWave,
  push: renderPush,
  firework: renderFirework,
  stage: renderStage,
  heart: renderHeart,
  guard: renderGuard,
  circle: renderCircle,
  spiral: renderSpiral,
  pulse: renderPulse,
  sequence: renderSequence,
  domino: renderDomino,
  impulse: renderImpulse,
  cube: renderCube,
  fill: renderFill,
  sphere: renderSphere,
  flag: renderFlag,
  clap: renderClap,
  rotate: renderRotate,
  swish: renderSwish,
  goo: renderGoo,
  comb: renderComb,
  pong: renderPong,
  rainbow: renderRainbow,
  ring: renderRing,
  hoop: renderHoop,
  flapper: renderFlapper,
  magic: renderMagic,
  jellyfish: renderJellyfish,
  trace: renderTrace,
  classic: renderClassic,
  whisper: renderWhisper,
  metro: renderMetro,
};

export function Spinner({
  variant,
  size = "md",
  loading = true,
  className,
  style,
  "aria-label": ariaLabel = "Loading",
  ...props
}: SpinnerProps) {
  if (!loading) {
    return null;
  }

  const sizeMap: Record<string, number> = { sm: 20, md: 40, lg: 60, xl: 80 };
  const resolvedSize = typeof size === "number" ? size : sizeMap[size] ?? 40;

  return (
    <div
      role="status"
      aria-label={ariaLabel}
      className={cn("inline-flex items-center justify-center", className)}
      style={style}
      {...props}
    >
      {renderers[variant]({ size: resolvedSize })}
    </div>
  );
}

import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const motion = (props: any) => keyframes`
  0% {
    transform: translateX(0) scale(1);
  }
  25% {
    transform: translateX(${props.size / 2}${props.sizeUnit}) scale(0.25);
  }
  50% {
    transform: translateX(0) scale(1);
  }
  75% {
    transform: translateX(${-props.size / 2}${props.sizeUnit}) scale(0.25);
  }
  100% {
    transform: translateX(0) scale(1);
  }
`;

const Wrapper = styled.div<any>`
  display: flex;
  justify-content: center;
  align-items: center;
  width: ${(props) => `${props.size}${props.sizeUnit}`};
  height: ${(props) => `${props.size / 2}${props.sizeUnit}`};
`;

const Ball = styled.div<any>`
  width: ${(props) => `${props.size / 3}${props.sizeUnit}`};
  height: ${(props) => `${props.size / 3}${props.sizeUnit}`};
  border-radius: 50%;
  background-color: ${(props) => props.color};
  animation: ${(props) => motion(props)} 3s cubic-bezier(0.165, 0.84, 0.44, 1) infinite;
`;

export function renderBall({ size }: InternalRenderProps): React.ReactNode {
  const s = size ?? 40;
  const color = "var(--spinner-color, #00ff89)";

  return (
    <Wrapper size={s} sizeUnit="px">
      <Ball color={color} size={s} sizeUnit="px" />
    </Wrapper>
  );
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const motion = (props: any) => keyframes`
  0% {
    width: ${props.size / 20}${props.sizeUnit}
  }
  50% {
    width: ${props.size / 6}${props.sizeUnit}
  }
  100% {
    width: ${props.size / 20}${props.sizeUnit}
  }
`;

const Wrapper = styled.div<any>`
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
  width: ${(props) => `${props.size}${props.sizeUnit}`};
  height: ${(props) => `${props.size}${props.sizeUnit}`};
`;

const Bar = styled.div<any>`
  position: absolute;
  top: ${(props) => `${props.y}${props.sizeUnit}`};
  left: ${(props) => `${props.x}${props.sizeUnit}`};
  width: ${(props) => `${props.size / 20}${props.sizeUnit}`};
  height: ${(props) => `${props.size}${props.sizeUnit}`};
  background-color: ${(props) => props.color};
  animation: ${motion} 1s cubic-bezier(0.165, 0.84, 0.44, 1) infinite;
  animation-delay: ${(props) => props.index * 0.15}s;
`;

const getBars = (countBars: number, color: string, size: number, sizeUnit: string) => {
  const bars = [];
  for (let i = 0; i < countBars; i++) {
    bars.push(
      <Bar
        color={color}
        size={size}
        sizeUnit={sizeUnit}
        x={i * (size / 5 + size / 25) - size / 12}
        key={i.toString()}
        index={i}
      />,
    );
  }
  return bars;
};

export function renderBars({ size }: InternalRenderProps): React.ReactNode {
  const s = size ?? 40;
  const color = "var(--spinner-color, #00ff89)";
  const countBars = 5;

  return <Wrapper size={s} sizeUnit="px">{getBars(countBars, color, s, "px")}</Wrapper>;
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const rotate = keyframes`
  0% {
    transform: rotate(0);
  }
  100% {
    transform: rotate(360deg);
  }
`;

const Wrapper = styled.div<any>`
  display: flex;
  justify-content: center;
  align-items: center;
  width: ${(props) => `${props.size}${props.sizeUnit}`};
  height: ${(props) => `${props.size}${props.sizeUnit}`};
  border: ${(props) => `${props.size / 5}${props.sizeUnit}`} solid ${(props) => props.color};
  border-right-color: transparent;
  border-radius: 50%;
  animation: ${rotate} 0.75s linear infinite;
`;

export function renderCircle({ size }: InternalRenderProps): React.ReactNode {
  const s = size ?? 30;
  const color = "var(--spinner-color, #fff)";

  return <Wrapper size={s} color={color} sizeUnit="px" />;
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const rotate = keyframes`
    50% {
        transform: rotate(180deg) scale(1.125);
    }
    100%{
        transform: rotate(360deg);
    }
`;

const move = (props: any) => keyframes`
    0% {
        transform: translateX(${props.x}${props.sizeUnit}) translateY(${props.y}${
    props.sizeUnit
}) scale(1.25) ;
    }
    5% {
        transform: translateX(${props.x}${props.sizeUnit}) translateY(${props.y}${
    props.sizeUnit
}) scale(1.75);
    }
    50% {
        transform: translateX(${props.x}${props.sizeUnit}) translateY(${props.y}${props.sizeUnit}) scale(.25);
    }
    55% {
        background-color: ${props.backColor};
        transform: translateX(${props.x}${props.sizeUnit}) translateY(${props.y}${props.sizeUnit}) scale(1) ;
    }
`;

const getBalls = ({ countBalls, radius, angle, frontColor, backColor, size, ballSize, sizeUnit }: any) => {
  const balls = [];
  const offset = ballSize / 2;
  for (let i = 0; i < countBalls; i++) {
    const y = Math.sin(angle * i * (Math.PI / 180)) * radius - offset;
    const x = Math.cos(angle * i * (Math.PI / 180)) * radius - offset;
    balls.push(
      <Ball
        frontColor={frontColor}
        backColor={backColor}
        ballSize={ballSize}
        size={size}
        sizeUnit={sizeUnit}
        x={y}
        y={x}
        key={i.toString()}
        index={i}
      />,
    );
  }
  return balls;
};

const Wrapper = styled.div`
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
    width: ${props => `${(props as any).size}${(props as any).sizeUnit}`};
    height: ${props => `${(props as any).size}${(props as any).sizeUnit}`};
    animation: ${rotate} 1.5s linear infinite;
`;

const Ball = styled.div`
    position: absolute;
    top: ${props => `${(props as any).size / 2}${(props as any).sizeUnit}`};
    left: ${props => `${(props as any).size / 2}${(props as any).sizeUnit}`};
    width: ${props => `${(props as any).ballSize}${(props as any).sizeUnit}`};
    height: ${props => `${(props as any).ballSize}${(props as any).sizeUnit}`};
    border-radius: 50%;
    background-color: ${props => (props as any).frontColor};
    transform: translateX(${props => `${(props as any).x}${(props as any).sizeUnit}`})
        translateY(${props => `${(props as any).y}${(props as any).sizeUnit}`});
    animation: ${props => move(props)} 2.5s cubic-bezier(0.075, 0.82, 0.165, 1) infinite;
    animation-delay: ${props => (props as any).index * 0.2}s;
`;

export function renderClap({ size }: InternalRenderProps) {
  const s = size ?? 30;
  const frontColor = "var(--spinner-color, #00ff89)";
  const backColor = "var(--spinner-secondary-color, #686769)";
  const radius = s / 2;
  const countBalls = 7;
  const ballSize = s / 5;
  const angle = 360 / countBalls;
  return <Wrapper size={s} sizeUnit="px">{getBalls({ countBalls, radius, angle, frontColor, backColor, size: s, ballSize, sizeUnit: "px" })}</Wrapper>;
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const fade = keyframes`
  0% {
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
`;

const Wrapper = styled.div`
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
  width: ${(props: any) => `${props.size}px`};
  height: ${(props: any) => `${props.size}px`};
`;

const Bar = styled.div`
  position: absolute;
  width: ${(props: any) => `${props.size / 10}px`};
  height: ${(props: any) => `${props.size / 4}px`};
  background-color: ${(props: any) => props.color};
  opacity: 0.05;
  transform: ${(props: any) => `rotate(${props.rotate}deg)`}
    ${(props: any) => `translate(0, ${props.translate}px)`};
  animation: ${fade} ${(props: any) => props.countBars * 0.06}s linear infinite;
  animation-delay: ${(props: any) => props.index * 0.06}s;
`;

export function renderClassic({ size }: InternalRenderProps): React.ReactNode {
  const spinnerSize = size ?? 30;
  const countBars = 16;
  const color = "var(--spinner-color, #fff)";
  const bars: React.ReactNode[] = [];

  for (let i = 0; i < countBars; i++) {
    const rotate = (360 / countBars) * i;
    const translate = -(spinnerSize / 2);
    bars.push(
      <Bar
        countBars={countBars}
        color={color}
        size={spinnerSize}
        rotate={rotate}
        translate={translate}
        key={i.toString()}
        index={i}
      />,
    );
  }

  return <Wrapper size={spinnerSize}>{bars}</Wrapper>;
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const rotate = () => keyframes`
  to {
    transform: rotate(450deg);
  }
`;

const Wrapper = styled.div`
  position: relative;
  width: ${(props: any) => `${props.size}px`};
  height: ${(props: any) => `${props.size / 5}px`};
`;

const Bar = styled.div`
  position: absolute;
  left: 0;
  width: ${(props: any) => `${props.size / 60}px`};
  height: ${(props: any) => `${props.size / 5}px`};
  left: ${(props: any) => `${props.index * 9}px`};
  transform-origin: center bottom;
  transform: rotate(-90deg);
  background-color: ${(props: any) => props.color};
  animation: ${rotate} 3s ease infinite;
  animation-delay: ${(props: any) => props.index * 0.05}s;
`;

export function renderComb({ size }: InternalRenderProps): React.ReactNode {
  const spinnerSize = size ?? 100;
  const countBars = spinnerSize / 9;
  const color = "var(--spinner-color, #fff)";
  const bars: React.ReactNode[] = [];

  for (let i = 0; i < countBars; i++) {
    bars.push(<Bar color={color} size={spinnerSize} key={i.toString()} index={i} />);
  }

  return <Wrapper size={spinnerSize}>{bars}</Wrapper>;
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const rotate = keyframes`
    from { transform: rotateX(0) rotateY(0); }
    to   { transform: rotateX(360deg) rotateY(360deg); }
`;

const Wrapper = styled.div`
    position: relative;
    display: flex;
    justify-content: center;
    align-items: center;
    width: ${props => `${(props as any).size}${(props as any).sizeUnit}`};
    height: ${props => `${(props as any).size}${(props as any).sizeUnit}`};
    perspective: ${props => `${(props as any).size * 4}${(props as any).sizeUnit}`};
`;

const CubeWrapper = styled.div`
    sposition: absolute;
    top: ${props => `${(props as any).y}${(props as any).sizeUnit}`};
    left: ${props => `${(props as any).x}${(props as any).sizeUnit}`};
    width: inherit;
    height: inherit;
`;

const Cube = styled.div`
    position: relative;
    width: ${props => `${(props as any).size}${(props as any).sizeUnit}`};
    height: ${props => `${(props as any).size}${(props as any).sizeUnit}`};
    transform-style: preserve-3d;
    animation: ${rotate} 3s cubic-bezier(0.68, -0.55, 0.265, 1.55) infinite;
`;

const rotateXCube = (props: any) => {
  if (props.top) {
    return 90;
  }
  if (props.bottom) {
    return -90;
  }
  return 0;
};

const rotateYCube = (props: any) => {
  if (props.left) {
    return 90;
  }
  if (props.right) {
    return -90;
  }
  if (props.back) {
    return 180;
  }
  return 0;
};

const Side = styled.div`
    backface-visibility: hidden;
    display: block;
    position: absolute;
    width: inherit;
    height: inherit;
    background-color: ${props => (props as any).color};
    transform: rotateX(${props => rotateXCube(props)}deg) rotateY(${props => rotateYCube(props)}deg)
        translateZ(${props => `${(props as any).size / 2}${(props as any).sizeUnit}`});
`;

export function renderCube({ size }: InternalRenderProps) {
  const s = size ?? 25;
  const frontColor = "var(--spinner-color, #00ff89)";
  const backColor = "var(--spinner-secondary-color, #4b4c56)";
  return (
    <Wrapper size={s} sizeUnit="px">
      <CubeWrapper x={0} y={0} sizeUnit="px">
        <Cube size={s} sizeUnit="px">
          <Side front={true} size={s} color={frontColor} sizeUnit="px" />
          <Side back={true} size={s} color={frontColor} sizeUnit="px" />
          <Side bottom={true} size={s} color={backColor} sizeUnit="px" />
          <Side top={true} size={s} color={backColor} sizeUnit="px" />
          <Side left={true} size={s} color={backColor} sizeUnit="px" />
          <Side right={true} size={s} color={backColor} sizeUnit="px" />
        </Cube>
      </CubeWrapper>
    </Wrapper>
  );
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const fall = (props: any) => keyframes`
    0% {
        transform: translateX(${props.translatesPoints[0]}${props.sizeUnit}) rotate(0deg);
        opacity: 0;
    }
    14.28% {
        transform: translateX(${props.translatesPoints[1]}${props.sizeUnit}) rotate(0deg);
        opacity: 1;
    }
    28.56% {
        transform: translateX(${props.translatesPoints[2]}${props.sizeUnit}) rotate(0deg);
        opacity: 1;
    }
    37.12% {
        transform: translateX(${props.translatesPoints[3]}${props.sizeUnit}) rotate(0deg);
        opacity: 1;
    }
    42.84% {
        transform: translateX(${props.translatesPoints[4]}${props.sizeUnit}) rotate(10deg);
        opacity: 1;
    }
    57.12% {
        transform: translateX(${props.translatesPoints[5]}${props.sizeUnit}) rotate(40deg);
        opacity: 1;
    }
    71.4% {
        transform: translateX(${props.translatesPoints[6]}${props.sizeUnit}) rotate(62deg);
        opacity: 1;
    }
    85.68% {
        transform: translateX(${props.translatesPoints[7]}${props.sizeUnit}) rotate(72deg);
        opacity: 1;
    }
    100% {
        transform: translateX(${props.translatesPoints[8]}${props.sizeUnit}) rotate(74deg);
        opacity: 0;
    }
`;

const getTranslatePositions = (countBars: number, size: number) => {
  const translates = [];
  for (let i = 0; i <= countBars + 1; i++) {
    translates.push(-i * (size / 8));
  }
  return translates;
};

const getBars = ({ countBars, rotatesPoints, translatesPoints, color, size, sizeUnit }: any) => {
  const bars = [];
  for (let i = 0; i < countBars; i++) {
    bars.push(
      <Bar
        color={color}
        size={size}
        translatesPoints={translatesPoints}
        rotate={rotatesPoints[i]}
        key={i.toString()}
        index={i}
        sizeUnit={sizeUnit}
      />,
    );
  }
  return bars;
};

const Wrapper = styled.div`
    position: relative;
    width: ${props => `${(props as any).size}${(props as any).sizeUnit}`};
    height: ${props => `${(props as any).size / 5}${(props as any).sizeUnit}`};
`;

const Bar = styled.div`
    position: absolute;
    right: 0;
    width: ${props => `${(props as any).size / 30}${(props as any).sizeUnit}`};
    height: ${props => `${(props as any).size / 5}${(props as any).sizeUnit}`};
    transform-origin: 50% 100%;
    background-color: ${props => (props as any).color};
    animation: ${fall} 3s linear infinite;
    animation-delay: ${props => (props as any).index * -0.42}s;
    transform: translateX(${props => `${(props as any).size - (props as any).index * 15}${(props as any).sizeUnit}`})
        rotate(${props => (props as any).rotate}deg);
    &:nth-child(1) {
        opacity: 0.22;
    }
`;

export function renderDomino({ size }: InternalRenderProps) {
  const s = size ?? 100;
  const color = "var(--spinner-color, #686769)";
  const countBars = 7;
  const rotatesPoints = [0, 0, 0, 10, 40, 60, 70];
  const translatesPoints = getTranslatePositions(countBars, s);
  return <Wrapper size={s} sizeUnit="px">{getBars({ countBars, rotatesPoints, translatesPoints, color, size: s, sizeUnit: "px" })}</Wrapper>;
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const rotate = keyframes`
    0% {
        transform: rotate(0deg);
    }
    25% {
        transform: rotate(180deg);
    }
    50% {
        transform: rotate(180deg);
    }
    75% {
        transform: rotate(360deg);
    }
    100% {
        transform: rotate(360deg);
    }
`;

const fill = keyframes`
    0% {
        height: 0%;
    }
    25% {
        height: 0%;
    }
    50% {
        height: 100%;
    }
    75% {
        height: 100%;
    }
    100% {
        height: 0%;
    }
`;

const Wrapper = styled.div`
    display: flex;
    align-items: flex-end;
    justify-content: center;
    width: ${props => `${(props as any).size}${(props as any).sizeUnit}`};
    height: ${props => `${(props as any).size}${(props as any).sizeUnit}`};
    border: ${props => `${(props as any).size / 8}${(props as any).sizeUnit}`} solid ${props => (props as any).color};
    animation: ${rotate} 3s cubic-bezier(0.77, 0, 0.175, 1) infinite;
`;

const Plane = styled.div`
    width: 100%;
    background-color: ${props => (props as any).color};
    animation: ${fill} 3s cubic-bezier(0.165, 0.84, 0.44, 1) infinite;
`;

export function renderFill({ size }: InternalRenderProps) {
  const s = size ?? 20;
  const color = "var(--spinner-color, #686769)";
  return <Wrapper size={s} color={color} sizeUnit="px"><Plane color={color} size={s} sizeUnit="px" /></Wrapper>;
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const fire = keyframes`
  0% {
    opacity: 1;
    transform: scale(0.1);
  }
  25% {
    opacity: 0.85;
  }
  100% {
    transform: scale(1);
    opacity: 0;
  }
`;

const Wrapper = styled.div<any>`
  border: ${(props) => `${props.size / 10}${props.sizeUnit}`} dotted ${(props) => props.color};
  display: flex;
  justify-content: center;
  align-items: center;
  width: ${(props) => `${props.size}${props.sizeUnit}`};
  height: ${(props) => `${props.size}${props.sizeUnit}`};
  border-radius: 50%;
  animation: ${fire} 1.25s cubic-bezier(0.165, 0.84, 0.44, 1) infinite;
`;

export function renderFirework({ size }: InternalRenderProps): React.ReactNode {
  const s = size ?? 40;
  const color = "var(--spinner-color, #fff)";

  return <Wrapper size={s} color={color} sizeUnit="px" />;
}

import styled, { keyframes } from "styled-components";
import type { InternalRenderProps } from "../types";

const wave = (props: any) => keyframes`
    0% {
        transform: translateY(0);
        opacity: 1;
    }
    50% {
        transform: translateY(${-props.size / 5}${props.sizeUnit});
